-- Save MJ: Queries (core SP call only)
DO $mj$
DECLARE
  p_Name_0de96cc7 VARCHAR(255);
  p_CategoryID_0de96cc7 UUID;
  p_UserQuestion_0de96cc7 TEXT;
  p_Description_0de96cc7 TEXT;
  p_SQL_0de96cc7 TEXT;
  p_TechnicalDescription_0de96cc7 TEXT;
  p_OriginalSQL_0de96cc7 TEXT;
  p_Feedback_0de96cc7 TEXT;
  p_Status_0de96cc7 VARCHAR(15);
  p_QualityRank_0de96cc7 INTEGER;
  p_ExecutionCostRank_0de96cc7 INTEGER;
  p_UsesTemplate_0de96cc7 BOOLEAN;
  p_AuditQueryRuns_0de96cc7 BOOLEAN;
  p_CacheEnabled_0de96cc7 BOOLEAN;
  p_CacheTTLMinutes_0de96cc7 INTEGER;
  p_CacheMaxSize_0de96cc7 INTEGER;
  p_EmbeddingVector_0de96cc7 TEXT;
  p_EmbeddingModelID_0de96cc7 UUID;
  p_CacheValidationSQL_0de96cc7 TEXT;
  p_SQLDialectID_0de96cc7 UUID;
  p_Reusable_0de96cc7 BOOLEAN;
  p_ID_0de96cc7 UUID;
BEGIN
  p_Name_0de96cc7 := 'GetArtifactVersionsByID';
  p_CategoryID_0de96cc7 := '5609FBC7-381C-4F9C-9C74-04B52C1FF3DA';
  p_UserQuestion_0de96cc7 := 'What are the full artifact version records for a given set of artifact version IDs?';
  p_Description_0de96cc7 := 'Returns artifact version fields (name, content mode, file ref, content, mime) joined with the parent artifact and artifact type (including ToolLibraryClass) for a supplied list of ArtifactVersionIDs.';
  p_SQL_0de96cc7 := '-- Get Artifact Versions By ID - Single optimized query
-- Returns all fields needed to construct InputArtifact records for agent context gathering.
-- Replaces a per-version loop that did two Load() calls (ArtifactVersion + Artifact) per row.
--
-- Parameters:
--   @versionIds: Array of ArtifactVersionIDs (rendered via sqlIn filter)

SELECT
    av."ID" as VersionID,
    av."Name" as VersionName,
    av."ContentMode",
    av."FileID",
    av."Content",
    av."MimeType",
    av."ForceToolsOnly",

    a."Name" as ArtifactName,
    a."Type" as TypeName,

    at."ToolLibraryClass",
    at."DefaultDeliveryMode"

FROM [__mj].[vwArtifactVersions] av
INNER JOIN [__mj].[vwArtifacts] a ON av."ArtifactID" = a."ID"
INNER JOIN [__mj].[vwArtifactTypes] at ON a."TypeID" = at."ID"

