-- Save MJ: Query SQLs (core SP call only)
DO $mj$
DECLARE
  p_QueryID_bc31766b UUID;
  p_SQLDialectID_bc31766b UUID;
  p_SQL_bc31766b TEXT;
  p_ID_bc31766b UUID;
BEGIN
  p_QueryID_bc31766b := '34D2D4D2-C727-4366-996F-3AAF87FC103E';
  p_SQLDialectID_bc31766b := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_bc31766b := '-- PostgreSQL variant: Get Artifact Versions By ID
-- Mirrors get-artifact-versions-by-id.sql for PG. Differences:
--   * `[__mj].[X]` → `__mj."X"` (schema brackets removed, view names quoted).
--   * Bare PascalCase column refs double-quoted to survive PG''s case-folding.

SELECT
    av."ID" AS "VersionID",
    av."Name" AS "VersionName",
    av."ContentMode",
    av."FileID",
    av."Content",
    av."MimeType",
    av."ForceToolsOnly",

    a."Name" AS "ArtifactName",
    a."Type" AS "TypeName",

    at."ToolLibraryClass",
    at."DefaultDeliveryMode"

FROM __mj."vwArtifactVersions" av
INNER JOIN __mj."vwArtifacts" a ON av."ArtifactID" = a."ID"
INNER JOIN __mj."vwArtifactTypes" at ON a."TypeID" = at."ID"

WHERE av."ID" IN {{ versionIds | sqlIn }}
';
  p_ID_bc31766b := '3659bd9a-71af-448e-8567-6e531ba58bba';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_bc31766b, p_SQLDialectID := p_SQLDialectID_bc31766b, p_SQL := p_SQL_bc31766b, p_ID := p_ID_bc31766b);
END $mj$;

